const normAr = (s) => s.replace(/[ً-ْٰ]/g, "").replace(/[إأآا]/g, "ا").replace(/ى/g, "ي").replace(/ة/g, "ه").replace(/[؟?.،,!:؛\-…()«»"']/g, "").replace(/\s+/g, " ").trim();
function buildBank(raw) {
  const out = {};
  for (const [cat, arr] of Object.entries(raw)) {
    const seen = new Set(); out[cat] = [];
    for (const it of arr) {
      const key = normAr(it.q);
      if (seen.has(key) || !it.opts || it.opts.length !== 4 || !it.opts.includes(it.a)) continue;
      seen.add(key); out[cat].push({ ...it, cat, id: `${cat}:${out[cat].length}` });
    }
  }
  return out;
}
