// ============ AUDIO (volume-aware) ============
class Aud {
  constructor() { this.ctx = null; this.on = true; this.sfxVol = 1; this.musicVol = 0.6; }
  init() { if (!this.ctx) { try { this.ctx = new (window.AudioContext || window.webkitAudioContext)(); } catch (e) { } } if (this.ctx && this.ctx.state === "suspended") this.ctx.resume(); }
  setVol(sfx, music) { if (sfx != null) this.sfxVol = sfx; if (music != null) this.musicVol = music; this.on = (this.sfxVol > 0); }
  t(f, d, type = "sine", v = 0.16, w = 0, g = null) { if (!this.on || !this.ctx) return; const vv = v * this.sfxVol; const tt = this.ctx.currentTime + w; const o = this.ctx.createOscillator(), gn = this.ctx.createGain(); o.type = type; o.frequency.setValueAtTime(f, tt); if (g) o.frequency.exponentialRampToValueAtTime(g, tt + d); gn.gain.setValueAtTime(0, tt); gn.gain.linearRampToValueAtTime(vv, tt + 0.012); gn.gain.exponentialRampToValueAtTime(0.0001, tt + d); o.connect(gn); gn.connect(this.ctx.destination); o.start(tt); o.stop(tt + d + 0.02); }
  tap() { this.init(); this.t(430, 0.06, "sine", 0.09); }
  nav() { this.init(); this.t(300, 0.08, "triangle", 0.09); this.t(470, 0.09, "sine", 0.06, 0.04); }
  correct() { this.init();[523, 659, 784, 1047].forEach((f, i) => this.t(f, 0.15, "sine", 0.13, i * 0.055)); }
  wrong() { this.init(); this.t(220, 0.18, "sawtooth", 0.1, 0, 130); this.t(175, 0.2, "sine", 0.07, 0.02); }
  reward() { this.init();[659, 784, 988, 1319, 1568].forEach((f, i) => this.t(f, 0.2, "triangle", 0.12, i * 0.07)); }
  levelup() { this.init();[523, 659, 784, 1047, 1319, 1568].forEach((f, i) => this.t(f, 0.28, "sine", 0.13, i * 0.085)); }
  win() { this.init();[784, 988, 1319, 1568, 2093].forEach((f, i) => this.t(f, 0.3, "triangle", 0.13, i * 0.1)); }
  tick() { this.init(); this.t(880, 0.04, "square", 0.05); }
  letter() { this.init(); this.t(620, 0.05, "sine", 0.08); }
  spin() { this.init(); for (let i = 0; i < 10; i++) this.t(500 + i * 40, 0.05, "square", 0.05, i * 0.08); }
  clue() { this.init();[660, 880, 1100].forEach((f, i) => this.t(f, 0.18, "triangle", 0.1, i * 0.08)); }
  portal() { this.init(); for (let i = 0; i < 14; i++) this.t(150 + i * 95, 0.24, "sine", 0.07, i * 0.07); this.t(64, 1.6, "sawtooth", 0.05); this.t(96, 1.6, "sine", 0.05, 0.1); }
  anomaly() { this.init(); this.t(392, 0.32, "triangle", 0.09); this.t(370, 0.45, "sine", 0.07, 0.12); this.t(196, 0.55, "sine", 0.06, 0.22); }
  chime() { this.init();[880, 1175, 1568].forEach((f, i) => this.t(f, 0.42, "sine", 0.08, i * 0.13)); }
}
