// ============ PLAY (standard MCQ + choose-question + word-builder) ============
function Play({ mode, cat, round, qi, setQi, p, update, playerTier, finishRound, addBurst, markSeen, setScreen, showToast }) {
  const accent = mode._cat?.color || mode.color || C.gold;
  if (mode.id === "builder") return <BuilderPlay {...{ mode, round, qi, setQi, accent, finishRound, markSeen, setScreen }} />;
  if (mode.id === "choose") return <ChoosePlay {...{ mode, round, qi, setQi, accent, finishRound, addBurst, markSeen, setScreen }} />;
  if (mode.id === "timed") return <TimedPlay {...{ mode, round, qi, setQi, accent, finishRound, addBurst, markSeen, setScreen }} />;
  return <StandardPlay {...{ mode, cat, round, qi, setQi, accent, p, update, finishRound, addBurst, markSeen, setScreen, showToast }} />;
}

function PlayHeader({ accent, mode, qi, total, setScreen, right, streak }) {
  return (
    <div style={{ padding: 16 }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 12 }}>
        <IconBtn icon="arrow" onClick={() => setScreen("hub")} />
        <div style={{ display: "flex", alignItems: "center", gap: 7, fontWeight: 800, color: accent }}><Icon d={I[mode.icon]} size={18} c={accent} />{mode.name}</div>
        <div style={{ minWidth: 42, textAlign: "left" }}>{streak > 1 && <span style={{ display: "inline-flex", alignItems: "center", gap: 3, color: C.amber, fontWeight: 800, fontSize: 13 }}><Icon d={I.flame} size={14} c={C.amber} />×{streak}</span>}</div>
      </div>
      <div style={{ display: "flex", gap: 5, marginBottom: 14 }}>{Array.from({ length: total }, (_, i) => <div key={i} style={{ flex: 1, height: 5, borderRadius: 3, background: i < qi ? accent : i === qi ? `${accent}88` : "rgba(150,170,220,0.14)", transition: "background .3s" }} />)}</div>
    </div>
  );
}

function StandardPlay({ mode, round, qi, setQi, accent, p, update, finishRound, addBurst, markSeen, setScreen, showToast }) {
  const cur = round[qi];
  const [opts, setOpts] = useState(() => shuffle(cur.opts));
  const [picked, setPicked] = useState(null);
  const [hidden, setHidden] = useState([]);
  const [hint, setHint] = useState(false);
  const [timer, setTimer] = useState(mode.time || 0);
  const [right, setRight] = useState(0);
  const [streak, setStreak] = useState(0);
  const lockRef = useRef(false);

  useEffect(() => { setOpts(shuffle(cur.opts)); setPicked(null); setHidden([]); setHint(false); setTimer(mode.time || 0); lockRef.current = false; }, [qi]);
  useEffect(() => {
    if (!mode.time || picked !== null) return;
    if (timer <= 0) { answer(-1, null); return; }
    if (timer <= 4) SFX.tick();
    const t = setTimeout(() => setTimer(x => x - 1), 1000); return () => clearTimeout(t);
  }, [timer, picked, mode.time]);

  const answer = (idx, ev) => {
    if (lockRef.current) return; lockRef.current = true;
    setPicked(idx);
    const ok = idx >= 0 && opts[idx] === cur.a;
    markSeen(cur.id, ok);
    if (ok) { SFX.correct(); setRight(r => r + 1); setStreak(s => s + 1); addBurst(ev, accent); } else { SFX.wrong(); setStreak(0); }
    setTimeout(() => { if (qi + 1 >= round.length) finishRound(right + (ok ? 1 : 0), round.length); else setQi(qi + 1); }, 1000);
  };

  // charge a helper's coin cost; refuse (with feedback) when the wallet can't cover it
  const spend = (cost) => {
    if (!p || !update) return true; // roulette embeds this screen without wallet wiring — helpers stay free there
    if (p.coins < cost) { SFX.wrong(); showToast && showToast("لا تكفي عملاتك لهذه المساعدة", C.amber); return false; }
    update((n) => { n.coins -= cost; });
    return true;
  };

  return (
    <div className="k-fade">
      <PlayHeader {...{ accent, mode, qi, total: round.length, setScreen, streak }} />
      <div style={{ padding: "0 16px" }}>
        {mode.time > 0 && <div style={{ marginBottom: 12 }}><div style={{ height: 7, borderRadius: 5, background: "rgba(150,170,220,0.12)", overflow: "hidden" }}><div style={{ height: "100%", width: `${(timer / mode.time) * 100}%`, background: timer <= 4 ? C.red : accent, transition: "width 1s linear", boxShadow: `0 0 10px ${timer <= 4 ? C.red : accent}` }} /></div></div>}
        <Panel glow={accent} style={{ padding: 24, textAlign: "center", minHeight: 120, display: "flex", flexDirection: "column", justifyContent: "center" }}>
          <div style={{ display: "flex", justifyContent: "center", gap: 8, alignItems: "center", marginBottom: 10 }}><span style={{ fontSize: 12, color: C.inkDim }}>{qi + 1} / {round.length}</span><TierTag d={cur.d} sm /></div>
          <div style={{ fontSize: 21, fontWeight: 900, lineHeight: 1.6 }}>{cur.q}</div>
          {hint && <div className="k-fade" style={{ marginTop: 12, fontSize: 13, color: C.green, display: "flex", justifyContent: "center", gap: 6, alignItems: "center" }}><Icon d={I.spark} size={15} c={C.green} />يبدأ بحرف «{cur.a[0]}» — {cur.a.length} حرفاً</div>}
        </Panel>
        <div style={{ display: "grid", gap: 10, marginTop: 14 }}>
          {opts.map((o, i) => {
            if (hidden.includes(i)) return <div key={i} style={{ height: 52 }} />;
            let bg = `linear-gradient(120deg,${C.card},${C.card2})`, bd = C.line, anim = "", ic = null, icc;
            if (picked !== null) { if (o === cur.a) { bg = `linear-gradient(120deg,${C.green}22,${C.green}0d)`; bd = C.green; anim = "k-correct"; ic = "check"; icc = C.green; } else if (i === picked) { bg = `linear-gradient(120deg,${C.red}22,${C.red}0d)`; bd = C.red; anim = "k-wrong"; ic = "x"; icc = C.red; } }
            return <button key={i} className={`k-press ${anim}`} disabled={picked !== null} onClick={(e) => answer(i, e)} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "15px 16px", borderRadius: 14, fontSize: 16, fontWeight: 700, background: bg, border: `1.5px solid ${bd}`, color: C.ink, cursor: picked === null ? "pointer" : "default", textAlign: "right", fontFamily: "inherit" }}><span>{o}</span>{ic && <Icon d={I[ic]} size={20} c={icc} />}</button>;
          })}
        </div>
        <Helpers {...{
          picked, hidden, hint, coins: p ? p.coins : Infinity,
          // helpers have a real coin cost — charged once, blocked when the wallet can't cover it
          onFifty: () => { if (picked !== null || hidden.length) return; if (!spend(30)) return; SFX.tap(); const w = opts.map((o, i) => i).filter(i => opts[i] !== cur.a); setHidden(shuffle(w).slice(0, 2)); },
          onHint: () => { if (hint) return; if (!spend(20)) return; SFX.tap(); setHint(true); },
          onSkip: () => { if (picked !== null) return; if (!spend(15)) return; SFX.tap(); markSeen(cur.id, false); if (qi + 1 >= round.length) finishRound(right, round.length); else setQi(qi + 1); },
        }} />
      </div>
    </div>
  );
}

// ============ MODE: TIMED (الوقت المحدود) — single 10-question race against a shared timer ============
// Rules: 10 questions per match · starts at 20s · +2s per correct · −5s per wrong (instant) ·
// hitting 0s = immediate Game Over · combo system tracks consecutive correct answers.
function TimedPlay({ mode, round, qi, setQi, accent, finishRound, addBurst, markSeen, setScreen }) {
  const START_MS = 20000, ADD_MS = 2000, PEN_MS = 5000; // 20s start, +2s correct, −5s wrong
  const cur = round[qi];
  const [opts, setOpts] = useState(() => shuffle(cur.opts));
  const [picked, setPicked] = useState(null);
  const [right, setRight] = useState(0);
  const [streak, setStreak] = useState(0);   // current combo (consecutive correct)
  const [bestCombo, setBestCombo] = useState(0);
  const [timeMs, setTimeMs] = useState(START_MS);
  const [over, setOver] = useState(false);
  const [won, setWon] = useState(false);
  const [delta, setDelta] = useState(null);   // floating ±time popup
  const [comboFx, setComboFx] = useState(0);   // key to retrigger the combo pop animation
  const timeRef = useRef(START_MS);            // authoritative remaining time (ms)
  const lastRef = useRef(0);
  const tickSecRef = useRef(Math.ceil(START_MS / 1000));
  const rightRef = useRef(0);
  const bestRef = useRef(0);
  const overRef = useRef(false);
  const lockRef = useRef(false);
  const rafRef = useRef(0);

  // new question — keep the shared match timer running, only reset the card
  useEffect(() => { setOpts(shuffle(cur.opts)); setPicked(null); lockRef.current = false; }, [qi]);

  // smooth real-time countdown via rAF (paused during the answer reveal and after game over)
  useEffect(() => {
    if (over || picked !== null) return;
    lastRef.current = performance.now();
    const loop = (now) => {
      const dt = now - lastRef.current; lastRef.current = now;
      timeRef.current = Math.max(0, timeRef.current - dt);
      setTimeMs(timeRef.current);
      const sec = Math.ceil(timeRef.current / 1000);
      if (sec !== tickSecRef.current) { tickSecRef.current = sec; if (sec > 0 && sec <= 5) SFX.tick(); }
      if (timeRef.current <= 0) { endGame(false); return; }    // immediate Game Over at zero
      rafRef.current = requestAnimationFrame(loop);
    };
    rafRef.current = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(rafRef.current);
  }, [over, picked]);

  const endGame = (win) => {
    if (overRef.current) return; overRef.current = true;
    cancelAnimationFrame(rafRef.current);
    setWon(win); setOver(true);
    win ? SFX.win() : SFX.wrong();
  };

  const showDelta = (txt, color) => {
    const id = Date.now() + Math.random(); setDelta({ id, txt, color });
    setTimeout(() => setDelta(d => (d && d.id === id ? null : d)), 1000);
  };

  const answer = (idx, ev) => {
    if (lockRef.current || over) return; lockRef.current = true;
    setPicked(idx);
    const ok = idx >= 0 && opts[idx] === cur.a;
    markSeen(cur.id, ok);
    if (ok) {
      SFX.correct();
      timeRef.current = timeRef.current + ADD_MS;            // +2s, instantly
      rightRef.current += 1; setRight(rightRef.current);
      const ns = streak + 1; setStreak(ns);                  // grow combo
      if (ns > bestRef.current) { bestRef.current = ns; setBestCombo(ns); }
      setComboFx(k => k + 1);
      if (ns >= 3 && ns % 3 === 0) SFX.reward();              // combo milestone flourish
      addBurst(ev, accent);
      showDelta(`+${ADD_MS / 1000}ث`, C.green);
    } else {
      SFX.wrong();
      timeRef.current = Math.max(0, timeRef.current - PEN_MS); // −5s, instantly
      setStreak(0);                                           // combo broken
      showDelta(`−${PEN_MS / 1000}ث`, C.red);
    }
    setTimeMs(timeRef.current);
    setTimeout(() => {
      if (overRef.current) return;
      if (timeRef.current <= 0) { endGame(false); return; }   // ran out on a wrong answer
      if (qi + 1 >= round.length) { endGame(true); return; }  // survived all 10
      setQi(qi + 1);
    }, 900);
  };

  const goResult = () => {
    const scoreMul = 1 + Math.floor(bestRef.current / 3) * 0.5; // combo boosts final rewards
    finishRound(rightRef.current, round.length, { scoreMul, headline: won ? "أكملت سباق الوقت!" : "انتهى الوقت!" });
  };

  if (over) {
    const vc = won ? C.gold : C.red;
    return (
      <div className="k-fade" style={{ padding: 22, display: "flex", flexDirection: "column", justifyContent: "center", minHeight: "100vh", textAlign: "center" }}>
        <div className="k-pop" style={{ display: "grid", placeItems: "center", width: 96, height: 96, borderRadius: 28, margin: "0 auto", background: `radial-gradient(circle,${vc}22,transparent)`, border: `1px solid ${vc}55` }}><Icon d={won ? I.trophy : I.hourglass} size={50} c={vc} /></div>
        <h2 style={{ fontSize: 28, fontWeight: 900, margin: "14px 0 4px", color: vc }}>{won ? "أكملت التحدي!" : "انتهى الوقت!"}</h2>
        <div style={{ color: C.inkDim, fontSize: 15 }}>{rightRef.current} من {round.length} إجابة صحيحة</div>
        <Panel style={{ marginTop: 18, display: "flex", justifyContent: "space-around", padding: 18 }}>
          <div className="k-rise"><Icon d={I.check} size={22} c={C.green} /><div style={{ fontSize: 21, fontWeight: 900, color: C.green, marginTop: 4 }}>{rightRef.current}</div><div style={{ fontSize: 11, color: C.inkDim }}>صحيحة</div></div>
          <div className="k-rise"><Icon d={I.flame} size={22} c={C.amber} /><div style={{ fontSize: 21, fontWeight: 900, color: C.amber, marginTop: 4 }}>×{bestRef.current}</div><div style={{ fontSize: 11, color: C.inkDim }}>أعلى كومبو</div></div>
        </Panel>
        <GoldBtn onClick={() => { SFX.nav(); goResult(); }} style={{ marginTop: 20, padding: "14px" }}>عرض النتيجة والمكافآت</GoldBtn>
        <DarkBtn onClick={() => setScreen("hub")} style={{ marginTop: 10 }}>الرئيسية</DarkBtn>
      </div>
    );
  }

  const secs = Math.ceil(timeMs / 1000);
  const low = timeMs <= 5000;
  const barPct = Math.max(0, Math.min(100, (timeMs / START_MS) * 100));
  const comboMul = (1 + Math.floor(streak / 3) * 0.5).toFixed(1);

  return (
    <div className="k-fade">
      <PlayHeader {...{ accent, mode, qi, total: round.length, setScreen, streak }} />
      <div style={{ padding: "0 16px" }}>
        {/* live shared timer */}
        <div style={{ marginBottom: 12 }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-end", marginBottom: 6 }}>
            <span style={{ display: "flex", alignItems: "center", gap: 6, fontSize: 12, color: C.inkDim }}><Icon d={I.hourglass} size={15} c={low ? C.red : accent} />الوقت المتبقّي</span>
            <span style={{ position: "relative", display: "inline-flex", alignItems: "baseline", gap: 3, fontSize: 30, fontWeight: 900, lineHeight: 1, color: low ? C.red : C.ink, transition: "color .2s", textShadow: low ? `0 0 14px ${C.red}88` : "none", fontVariantNumeric: "tabular-nums" }}>
              {secs}<span style={{ fontSize: 13, fontWeight: 800, color: C.inkDim }}>ث</span>
              {delta && <span key={delta.id} className="k-delta" style={{ left: "50%", top: -10, transform: "translateX(-50%)", fontSize: 17, fontWeight: 900, color: delta.color, whiteSpace: "nowrap", textShadow: `0 0 10px ${delta.color}66` }}>{delta.txt}</span>}
            </span>
          </div>
          <div className={low ? "k-shake-bar" : ""} style={{ height: 12, borderRadius: 7, background: "rgba(150,170,220,0.12)", overflow: "hidden", border: `1px solid ${low ? C.red + "55" : "transparent"}` }}>
            <div style={{ height: "100%", width: `${barPct}%`, borderRadius: 7, background: low ? `linear-gradient(90deg,${C.red},${C.rose})` : `linear-gradient(90deg,${accent},${C.gold})`, boxShadow: `0 0 14px ${low ? C.red : accent}`, transition: picked !== null ? "width .25s cubic-bezier(.2,.9,.2,1)" : "none" }} />
          </div>
        </div>

        {/* combo bonus banner */}
        {streak >= 2 && (
          <div key={comboFx} className="k-combo" style={{ display: "flex", justifyContent: "center", marginBottom: 12 }}>
            <span style={{ display: "inline-flex", alignItems: "center", gap: 7, padding: "6px 16px", borderRadius: 999, background: `linear-gradient(120deg,${C.amber}22,${C.gold}11)`, border: `1px solid ${C.amber}66`, color: C.amber, fontWeight: 900, fontSize: 14, boxShadow: `0 0 18px ${C.amber}33` }}>
              <Icon d={I.flame} size={16} c={C.amber} fill={C.amber} />كومبو ×{streak}{streak >= 3 ? ` · مكافأة ×${comboMul}` : ""}
            </span>
          </div>
        )}

        <Panel glow={accent} style={{ padding: 24, textAlign: "center", minHeight: 120, display: "flex", flexDirection: "column", justifyContent: "center" }}>
          <div style={{ display: "flex", justifyContent: "center", gap: 8, alignItems: "center", marginBottom: 10 }}><span style={{ fontSize: 12, color: C.inkDim }}>{qi + 1} / {round.length}</span><TierTag d={cur.d} sm /></div>
          <div style={{ fontSize: 21, fontWeight: 900, lineHeight: 1.6 }}>{cur.q}</div>
        </Panel>
        <div style={{ display: "grid", gap: 10, marginTop: 14 }}>
          {opts.map((o, i) => {
            let bg = `linear-gradient(120deg,${C.card},${C.card2})`, bd = C.line, anim = "", ic = null, icc;
            if (picked !== null) { if (o === cur.a) { bg = `linear-gradient(120deg,${C.green}22,${C.green}0d)`; bd = C.green; anim = "k-correct"; ic = "check"; icc = C.green; } else if (i === picked) { bg = `linear-gradient(120deg,${C.red}22,${C.red}0d)`; bd = C.red; anim = "k-wrong"; ic = "x"; icc = C.red; } }
            return <button key={i} className={`k-press ${anim}`} disabled={picked !== null} onClick={(e) => answer(i, e)} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "15px 16px", borderRadius: 14, fontSize: 16, fontWeight: 700, background: bg, border: `1.5px solid ${bd}`, color: C.ink, cursor: picked === null ? "pointer" : "default", textAlign: "right", fontFamily: "inherit" }}><span>{o}</span>{ic && <Icon d={I[ic]} size={20} c={icc} />}</button>;
          })}
        </div>
      </div>
    </div>
  );
}

function ChoosePlay({ mode, round, qi, setQi, accent, finishRound, addBurst, markSeen, setScreen }) {
  const cur = round[qi];
  const [picked, setPicked] = useState(null);
  const [right, setRight] = useState(0);
  const [streak, setStreak] = useState(0);
  const lockRef = useRef(false);
  useEffect(() => { setPicked(null); lockRef.current = false; }, [qi]);
  const answer = (i, ev) => {
    if (lockRef.current) return; lockRef.current = true; setPicked(i);
    const ok = cur.options[i] === cur.correctQ; markSeen(cur.id, ok);
    if (ok) { SFX.correct(); setRight(r => r + 1); setStreak(s => s + 1); addBurst(ev, accent); } else { SFX.wrong(); setStreak(0); }
    setTimeout(() => { if (qi + 1 >= round.length) finishRound(right + (ok ? 1 : 0), round.length, { scoreMul: 1 + Math.floor((streak + (ok ? 1 : 0)) / 3) }); else setQi(qi + 1); }, 1100);
  };
  const mult = 1 + Math.floor(streak / 2);
  return (
    <div className="k-fade">
      <PlayHeader {...{ accent, mode, qi, total: round.length, setScreen, streak }} />
      <div style={{ padding: "0 16px" }}>
        <div style={{ textAlign: "center", marginBottom: 10, fontSize: 12, color: C.inkDim }}>اختر السؤال الذي تكون إجابته:</div>
        <Panel glow={accent} style={{ padding: 22, textAlign: "center" }}>
          <div style={{ fontSize: 12, color: accent, marginBottom: 6 }}>الإجابة</div>
          <div style={{ fontSize: 26, fontWeight: 900 }}>{cur.answer}</div>
          {streak >= 2 && <div style={{ marginTop: 8, fontSize: 12, color: C.amber, fontWeight: 800 }}>مضاعف النقاط ×{mult}</div>}
        </Panel>
        <div style={{ display: "grid", gap: 10, marginTop: 14 }}>
          {cur.options.map((o, i) => {
            let bg = `linear-gradient(120deg,${C.card},${C.card2})`, bd = C.line, anim = "", ic = null, icc;
            if (picked !== null) { if (o === cur.correctQ) { bg = `linear-gradient(120deg,${C.green}22,${C.green}0d)`; bd = C.green; anim = "k-correct"; ic = "check"; icc = C.green; } else if (i === picked) { bg = `linear-gradient(120deg,${C.red}22,${C.red}0d)`; bd = C.red; anim = "k-wrong"; ic = "x"; icc = C.red; } }
            return <button key={i} className={`k-press ${anim}`} disabled={picked !== null} onClick={(e) => answer(i, e)} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", gap: 8, padding: "15px 16px", borderRadius: 14, fontSize: 15.5, fontWeight: 700, background: bg, border: `1.5px solid ${bd}`, color: C.ink, cursor: picked === null ? "pointer" : "default", textAlign: "right", fontFamily: "inherit" }}><span style={{ flex: 1 }}>{o}</span>{ic && <Icon d={I[ic]} size={20} c={icc} />}</button>;
          })}
        </div>
      </div>
    </div>
  );
}

function BuilderPlay({ mode, round, qi, setQi, accent, finishRound, markSeen, setScreen }) {
  const cur = round[qi];
  const [pool, setPool] = useState(() => cur.pool.map((ch, i) => ({ ch, i, used: false })));
  const [built, setBuilt] = useState([]);
  const [status, setStatus] = useState(null);
  const [right, setRight] = useState(0);
  const [hintsUsed, setHintsUsed] = useState(0);
  useEffect(() => { setPool(cur.pool.map((ch, i) => ({ ch, i, used: false }))); setBuilt([]); setStatus(null); setHintsUsed(0); }, [qi]);

  const tapLetter = (idx) => {
    if (status) return; const slot = pool[idx]; if (slot.used) return;
    SFX.letter();
    setPool(pl => pl.map((s, i) => i === idx ? { ...s, used: true } : s));
    setBuilt(b => [...b, { ch: slot.ch, poolIdx: idx }]);
  };
  const removeAt = (k) => { if (status) return; SFX.tap(); const item = built[k]; setBuilt(b => b.filter((_, i) => i !== k)); setPool(pl => pl.map((s, i) => i === item.poolIdx ? { ...s, used: false } : s)); };
  const clear = () => { if (status) return; SFX.tap(); setBuilt([]); setPool(pl => pl.map(s => ({ ...s, used: false }))); };
  const useHint = () => {
    if (status || hintsUsed >= cur.answer.length) return; SFX.tap();
    const need = cur.answer.slice(0, hintsUsed + 1).split("");
    let freshPool = cur.pool.map((ch, i) => ({ ch, i, used: false }));
    const nb = [];
    for (const L of need) { const slot = freshPool.find(s => !s.used && s.ch === L); if (slot) { slot.used = true; nb.push({ ch: L, poolIdx: slot.i }); } }
    setPool(freshPool); setBuilt(nb); setHintsUsed(h => h + 1);
  };
  const submit = () => {
    const word = built.map(b => b.ch).join("");
    if (word === cur.answer) { SFX.correct(); setStatus("ok"); setRight(r => r + 1); markSeen(cur.id, true); setTimeout(() => { if (qi + 1 >= round.length) finishRound(right + 1, round.length); else setQi(qi + 1); }, 1100); }
    else { SFX.wrong(); setStatus("bad"); setTimeout(() => setStatus(null), 700); }
  };
  const canSubmit = built.length === cur.answer.length;

  return (
    <div className="k-fade">
      <PlayHeader {...{ accent, mode, qi, total: round.length, setScreen, streak: 0 }} />
      <div style={{ padding: "0 16px" }}>
        <Panel glow={accent} style={{ padding: 20, textAlign: "center" }}>
          <div style={{ display: "flex", justifyContent: "center", gap: 8, alignItems: "center", marginBottom: 8 }}><span style={{ fontSize: 12, color: C.inkDim }}>{qi + 1} / {round.length}</span><TierTag d={cur.d} sm /></div>
          <div style={{ fontSize: 18, fontWeight: 800, lineHeight: 1.6 }}>{cur.clue}</div>
        </Panel>
        <div style={{ display: "flex", justifyContent: "center", gap: 7, flexWrap: "wrap", margin: "20px 0 6px" }}>
          {Array.from({ length: cur.answer.length }, (_, k) => {
            const b = built[k];
            const col = status === "ok" ? C.green : status === "bad" ? C.red : b ? accent : C.line;
            return <div key={k} onClick={() => b && removeAt(k)} className={status === "bad" ? "k-wrong" : ""} style={{ width: 42, height: 52, borderRadius: 12, border: `2px solid ${col}`, background: b ? `${col}1c` : "rgba(150,170,220,0.05)", display: "grid", placeItems: "center", fontSize: 24, fontWeight: 900, cursor: b ? "pointer" : "default", transition: "all .2s", boxShadow: b ? `0 0 12px ${col}33` : "none" }}>{b?.ch || ""}</div>;
          })}
        </div>
        <div style={{ textAlign: "center", height: 18, fontSize: 12, color: status === "ok" ? C.green : C.inkDim, fontWeight: 700 }}>{status === "ok" ? "إجابة صحيحة" : ""}</div>
        <div style={{ display: "flex", justifyContent: "center", gap: 9, flexWrap: "wrap", marginTop: 14 }}>
          {pool.map((s, i) => (
            <button key={i} className="k-press k-letter" disabled={s.used} onClick={() => tapLetter(i)} style={{ width: 48, height: 56, borderRadius: 13, fontSize: 25, fontWeight: 900, fontFamily: "inherit", cursor: s.used ? "default" : "pointer", color: s.used ? C.inkFaint : "#1c1407", background: s.used ? "rgba(150,170,220,0.06)" : `linear-gradient(135deg,${C.goldHi},${C.goldDeep})`, border: s.used ? `1px solid ${C.line}` : "none", boxShadow: s.used ? "none" : `0 5px 14px ${C.gold}33`, opacity: s.used ? .4 : 1, transition: "all .2s" }}>{s.used ? "" : s.ch}</button>
          ))}
        </div>
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 9, marginTop: 22 }}>
          <DarkBtn icon="spark" onClick={useHint} disabled={hintsUsed >= cur.answer.length}>تلميح</DarkBtn>
          <DarkBtn icon="trash" onClick={clear}>مسح</DarkBtn>
          <GoldBtn onClick={submit} disabled={!canSubmit}>تحقّق</GoldBtn>
        </div>
      </div>
    </div>
  );
}

function Helpers({ picked, hidden, hint, onFifty, onHint, onSkip }) {
  return (
    <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 9, marginTop: 16 }}>
      <button className="k-press" disabled={picked !== null || hidden.length} onClick={onFifty} style={hStyle(picked === null && !hidden.length)}><Icon d={I.swords} size={18} c={C.gold} /><span style={{ fontSize: 12, fontWeight: 700 }}>حذف خيارين</span><span style={hCost}><Icon d={I.coin} size={11} c={C.gold} />30</span></button>
      <button className="k-press" disabled={hint} onClick={onHint} style={hStyle(!hint)}><Icon d={I.spark} size={18} c={C.gold} /><span style={{ fontSize: 12, fontWeight: 700 }}>تلميح</span><span style={hCost}><Icon d={I.coin} size={11} c={C.gold} />20</span></button>
      <button className="k-press" disabled={picked !== null} onClick={onSkip} style={hStyle(picked === null)}><Icon d={I.arrow} size={18} c={C.gold} /><span style={{ fontSize: 12, fontWeight: 700 }}>تخطٍّ</span><span style={hCost}><Icon d={I.coin} size={11} c={C.gold} />15</span></button>
    </div>
  );
}
const hStyle = (en) => ({ display: "flex", flexDirection: "column", alignItems: "center", gap: 4, padding: "10px 4px", borderRadius: 13, background: "rgba(150,170,220,0.06)", border: `1px solid ${C.line}`, color: C.ink, cursor: en ? "pointer" : "not-allowed", opacity: en ? 1 : .4, fontFamily: "inherit" });
const hCost = { fontSize: 10, color: C.inkDim, display: "flex", alignItems: "center", gap: 3 };

// ============ CHALLENGE (pass-and-play multiplayer) ============
function ChallengeSetup({ mode, playerTier, diff, seen, setScreen, markSeen }) {
  const [names, setNames] = useState(["", ""]);
  const [extraQs, setExtraQs] = useState([]);
  const [showAdd, setShowAdd] = useState(false);
  const [draft, setDraft] = useState({ q: "", a: "", w1: "", w2: "", w3: "" });
  const [started, setStarted] = useState(false);

  const setName = (i, v) => setNames(n => n.map((x, k) => k === i ? v : x));
  const addPlayer = () => names.length < 6 && setNames(n => [...n, ""]);
  const rmPlayer = (i) => names.length > 2 && setNames(n => n.filter((_, k) => k !== i));
  const valid = names.filter(n => n.trim()).length >= 2;

  const addQ = () => {
    if (!draft.q.trim() || !draft.a.trim() || !draft.w1.trim() || !draft.w2.trim() || !draft.w3.trim()) return;
    SFX.tap();
    setExtraQs(e => [...e, { q: draft.q.trim(), a: draft.a.trim(), opts: [draft.a.trim(), draft.w1.trim(), draft.w2.trim(), draft.w3.trim()], d: 3, id: `custom:${e.length}` }]);
    setDraft({ q: "", a: "", w1: "", w2: "", w3: "" }); setShowAdd(false);
  };

  const start = () => {
    const players = names.map(n => n.trim()).filter(Boolean);
    const base = selectQ(ALL_Q, seen, diff.tier, Math.max(2, mode.n - extraQs.length));
    const all = shuffle([...extraQs, ...base]).slice(0, Math.max(extraQs.length + 2, mode.n));
    setStarted({ players, questions: all });
  };

  if (started) return <ChallengePlay {...{ players: started.players, questions: started.questions, setScreen, markSeen }} />;

  const inputStyle = { width: "100%", padding: "11px 13px", borderRadius: 11, background: "rgba(150,170,220,0.08)", border: `1px solid ${C.line}`, color: C.ink, fontSize: 14, fontFamily: "inherit", outline: "none" };
  return (
    <div className="k-fade" style={{ padding: 16 }}>
      <Header title="طور التحدي" onBack={() => setScreen("hub")} icon="versus" color={C.rose} />
      <div style={{ fontSize: 13, color: C.inkDim, marginBottom: 14 }}>لعب جماعي على جهاز واحد · بالتناوب · أدخلوا الأسماء</div>
      <div style={{ display: "grid", gap: 10 }}>
        {names.map((n, i) => (
          <div key={i} style={{ display: "flex", gap: 8, alignItems: "center" }}>
            <div style={{ display: "grid", placeItems: "center", width: 36, height: 36, borderRadius: 10, background: `${[C.gold, C.cyan, C.rose, C.green, C.violet, C.amber][i]}22`, color: [C.gold, C.cyan, C.rose, C.green, C.violet, C.amber][i], fontWeight: 900, fontSize: 14, flexShrink: 0 }}>{i + 1}</div>
            <input value={n} onChange={e => setName(i, e.target.value)} placeholder={`اسم اللاعب ${i + 1}`} style={inputStyle} />
            {names.length > 2 && <button className="k-press" onClick={() => rmPlayer(i)} style={{ display: "grid", placeItems: "center", width: 36, height: 36, borderRadius: 10, background: "rgba(150,170,220,0.06)", border: `1px solid ${C.line}`, cursor: "pointer" }}><Icon d={I.x} size={16} c={C.red} /></button>}
          </div>
        ))}
      </div>
      {names.length < 6 && <button className="k-press" onClick={addPlayer} style={{ marginTop: 10, width: "100%", display: "flex", alignItems: "center", justifyContent: "center", gap: 6, padding: "10px", borderRadius: 11, background: "transparent", border: `1px dashed ${C.line2}`, color: C.inkDim, cursor: "pointer", fontFamily: "inherit", fontWeight: 700, fontSize: 13 }}><Icon d={I.plus} size={16} c={C.inkDim} />إضافة لاعب</button>}
      <div style={{ marginTop: 20 }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}>
          <span style={{ fontSize: 14, fontWeight: 800 }}>أسئلة اللاعبين <span style={{ color: C.inkDim, fontWeight: 400 }}>(اختياري)</span></span>
          {extraQs.length > 0 && <span style={{ fontSize: 12, color: C.gold }}>{extraQs.length} مضاف</span>}
        </div>
        {extraQs.map((q, i) => <div key={i} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "9px 12px", borderRadius: 10, background: "rgba(150,170,220,0.05)", border: `1px solid ${C.line}`, marginBottom: 6 }}><span style={{ fontSize: 13 }}>{q.q}</span><Icon d={I.check} size={16} c={C.green} /></div>)}
        {!showAdd ? (
          <button className="k-press" onClick={() => { SFX.tap(); setShowAdd(true); }} style={{ width: "100%", display: "flex", alignItems: "center", justifyContent: "center", gap: 6, padding: "10px", borderRadius: 11, background: "transparent", border: `1px dashed ${C.line2}`, color: C.inkDim, cursor: "pointer", fontFamily: "inherit", fontWeight: 700, fontSize: 13 }}><Icon d={I.plus} size={16} c={C.inkDim} />أضف سؤالاً خاصاً</button>
        ) : (
          <Panel style={{ padding: 13, display: "grid", gap: 8 }}>
            <input value={draft.q} onChange={e => setDraft({ ...draft, q: e.target.value })} placeholder="السؤال" style={inputStyle} />
            <input value={draft.a} onChange={e => setDraft({ ...draft, a: e.target.value })} placeholder="الإجابة الصحيحة" style={{ ...inputStyle, border: `1px solid ${C.green}55` }} />
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 8 }}>
              <input value={draft.w1} onChange={e => setDraft({ ...draft, w1: e.target.value })} placeholder="خيار خاطئ" style={inputStyle} />
              <input value={draft.w2} onChange={e => setDraft({ ...draft, w2: e.target.value })} placeholder="خيار خاطئ" style={inputStyle} />
              <input value={draft.w3} onChange={e => setDraft({ ...draft, w3: e.target.value })} placeholder="خيار خاطئ" style={inputStyle} />
            </div>
            <div style={{ display: "flex", gap: 8 }}><GoldBtn sm onClick={addQ}>حفظ السؤال</GoldBtn><DarkBtn onClick={() => setShowAdd(false)} style={{ width: "auto", padding: "8px 14px" }}>إلغاء</DarkBtn></div>
          </Panel>
        )}
      </div>
      <GoldBtn onClick={() => { SFX.nav(); start(); }} disabled={!valid} style={{ marginTop: 22, padding: "15px" }}>ابدأ التحدي ({names.filter(n => n.trim()).length} لاعبين)</GoldBtn>
    </div>
  );
}

function ChallengePlay({ players, questions, setScreen, markSeen }) {
  const [turn, setTurn] = useState(0);
  const [qi, setQi] = useState(0);
  const [phase, setPhase] = useState("handoff");
  const [opts, setOpts] = useState(() => shuffle(questions[0].opts));
  const [picked, setPicked] = useState(null);
  const [tStart, setTStart] = useState(0);
  const [scores, setScores] = useState(players.map(() => ({ right: 0, total: 0, timeSum: 0, fastest: Infinity })));
  const lockRef = useRef(false);

  const curPlayer = turn % players.length;
  const cur = questions[qi];
  const isLast = qi >= questions.length - 1 && curPlayer === players.length - 1;

  const beginAnswer = () => { SFX.tap(); setOpts(shuffle(cur.opts)); setPicked(null); lockRef.current = false; setTStart(Date.now()); setPhase("answer"); };
  const answer = (i) => {
    if (lockRef.current) return; lockRef.current = true;
    const dt = (Date.now() - tStart) / 1000;
    setPicked(i); markSeen && cur.id && markSeen(cur.id, opts[i] === cur.a);
    const ok = opts[i] === cur.a;
    if (ok) SFX.correct(); else SFX.wrong();
    setScores(sc => sc.map((s, k) => k === curPlayer ? { right: s.right + (ok ? 1 : 0), total: s.total + 1, timeSum: s.timeSum + dt, fastest: ok ? Math.min(s.fastest, dt) : s.fastest } : s));
    setPhase("reveal");
  };
  const advance = () => {
    SFX.nav();
    if (curPlayer === players.length - 1 && qi >= questions.length - 1) { setPhase("done"); SFX.win(); return; }
    if (curPlayer === players.length - 1) { setQi(qi + 1); }
    setTurn(turn + 1); setPhase("handoff");
  };

  if (phase === "done") return <ChallengeResult {...{ players, scores, setScreen }} />;
  const pc = [C.gold, C.cyan, C.rose, C.green, C.violet, C.amber][curPlayer];
  return (
    <div className="k-fade" style={{ padding: 16 }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 14 }}>
        <IconBtn icon="arrow" onClick={() => setScreen("hub")} />
        <span style={{ fontWeight: 800, color: C.rose }}>طور التحدي</span>
        <span style={{ fontSize: 13, color: C.inkDim }}>سؤال {qi + 1}/{questions.length}</span>
      </div>
      <div className="k-scroll" style={{ display: "flex", gap: 8, overflowX: "auto", paddingBottom: 8, marginBottom: 6 }}>
        {players.map((nm, k) => <div key={k} style={{ flexShrink: 0, padding: "7px 12px", borderRadius: 11, background: k === curPlayer ? `${pc}1c` : "rgba(150,170,220,0.06)", border: `1px solid ${k === curPlayer ? pc : C.line}` }}><div style={{ fontSize: 11, color: C.inkDim }}>{nm}</div><div style={{ fontSize: 16, fontWeight: 900, color: [C.gold, C.cyan, C.rose, C.green, C.violet, C.amber][k] }}>{scores[k].right}</div></div>)}
      </div>
      {phase === "handoff" && (
        <div className="k-fade" style={{ display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", minHeight: 360, textAlign: "center" }}>
          <div style={{ display: "grid", placeItems: "center", width: 80, height: 80, borderRadius: 24, background: `${pc}1c`, border: `1px solid ${pc}55`, marginBottom: 16 }}><Icon d={I.user} size={40} c={pc} /></div>
          <div style={{ fontSize: 14, color: C.inkDim }}>دور اللاعب</div>
          <div style={{ fontSize: 28, fontWeight: 900, color: pc, margin: "4px 0 20px" }}>{players[curPlayer]}</div>
          <GoldBtn onClick={beginAnswer} style={{ width: 200 }}>أنا جاهز</GoldBtn>
        </div>
      )}
      {(phase === "answer" || phase === "reveal") && (
        <div className="k-fade">
          <Panel glow={pc} style={{ padding: 22, textAlign: "center", minHeight: 110, display: "flex", flexDirection: "column", justifyContent: "center" }}>
            <div style={{ display: "flex", justifyContent: "center", gap: 8, alignItems: "center", marginBottom: 8 }}><span style={{ fontSize: 12, color: pc, fontWeight: 700 }}>{players[curPlayer]}</span><TierTag d={cur.d || 3} sm /></div>
            <div style={{ fontSize: 20, fontWeight: 900, lineHeight: 1.6 }}>{cur.q}</div>
          </Panel>
          <div style={{ display: "grid", gap: 10, marginTop: 14 }}>
            {opts.map((o, i) => {
              let bg = `linear-gradient(120deg,${C.card},${C.card2})`, bd = C.line, ic = null, icc;
              if (phase === "reveal") { if (o === cur.a) { bg = `linear-gradient(120deg,${C.green}22,${C.green}0d)`; bd = C.green; ic = "check"; icc = C.green; } else if (i === picked) { bg = `linear-gradient(120deg,${C.red}22,${C.red}0d)`; bd = C.red; ic = "x"; icc = C.red; } }
              return <button key={i} className="k-press" disabled={phase === "reveal"} onClick={() => answer(i)} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "15px 16px", borderRadius: 14, fontSize: 16, fontWeight: 700, background: bg, border: `1.5px solid ${bd}`, color: C.ink, cursor: phase === "answer" ? "pointer" : "default", textAlign: "right", fontFamily: "inherit" }}><span>{o}</span>{ic && <Icon d={I[ic]} size={20} c={icc} />}</button>;
            })}
          </div>
          {phase === "reveal" && <GoldBtn onClick={advance} style={{ marginTop: 16 }}>{isLast ? "النتائج النهائية" : "اللاعب التالي"}</GoldBtn>}
        </div>
      )}
    </div>
  );
}

function ChallengeResult({ players, scores, setScreen }) {
  const ranked = players.map((nm, k) => ({ nm, ...scores[k], acc: scores[k].total ? scores[k].right / scores[k].total : 0, fastest: scores[k].fastest === Infinity ? null : scores[k].fastest })).sort((a, b) => b.right - a.right || a.timeSum - b.timeSum);
  const fastestOverall = ranked.reduce((m, r) => r.fastest != null && r.fastest < (m?.fastest ?? Infinity) ? r : m, null);
  const medals = [C.gold, "#c0c7d4", "#cd7f47"];
  const podiumOrder = [1, 0, 2];
  return (
    <div className="k-fade" style={{ padding: 16 }}>
      <div style={{ textAlign: "center", padding: "10px 0 4px" }}>
        <div className="k-pop" style={{ display: "inline-grid", placeItems: "center", width: 76, height: 76, borderRadius: 24, background: `radial-gradient(circle,${C.gold}26,transparent)`, border: `1px solid ${C.gold}44` }}><Icon d={I.trophy} size={42} c={C.gold} /></div>
        <h2 style={{ fontSize: 24, fontWeight: 900, margin: "12px 0 2px", color: C.gold }}>الفائز: {ranked[0].nm}</h2>
        <div style={{ color: C.inkDim, fontSize: 13 }}>بنتيجة {ranked[0].right} وإجابة دقّتها {Math.round(ranked[0].acc * 100)}%</div>
      </div>
      <div style={{ display: "flex", justifyContent: "center", alignItems: "flex-end", gap: 10, margin: "20px 0" }}>
        {podiumOrder.map((pos) => { const r = ranked[pos]; if (!r) return <div key={pos} style={{ flex: 1 }} />; const h = pos === 0 ? 110 : pos === 1 ? 80 : 64; return (
          <div key={pos} className="k-rise" style={{ flex: 1, textAlign: "center" }}>
            <div style={{ display: "grid", placeItems: "center", width: 46, height: 46, borderRadius: 14, margin: "0 auto 8px", background: `${medals[pos]}22`, border: `1px solid ${medals[pos]}66`, color: medals[pos], fontWeight: 900 }}>{pos + 1}</div>
            <div style={{ fontSize: 13, fontWeight: 800, marginBottom: 6 }}>{r.nm}</div>
            <div style={{ height: h, borderRadius: "12px 12px 0 0", background: `linear-gradient(180deg,${medals[pos]}33,${medals[pos]}0d)`, border: `1px solid ${medals[pos]}44`, borderBottom: "none", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "flex-start", paddingTop: 10 }}>
              <span style={{ fontSize: 22, fontWeight: 900, color: medals[pos] }}>{r.right}</span><span style={{ fontSize: 10, color: C.inkDim }}>نقطة</span>
            </div>
          </div>
        ); })}
      </div>
      <div style={{ display: "grid", gap: 8 }}>
        {ranked.map((r, i) => (
          <Panel key={i} style={{ padding: 12, display: "flex", alignItems: "center", gap: 12 }} glow={i === 0 ? C.gold : null}>
            <div style={{ display: "grid", placeItems: "center", width: 32, height: 32, borderRadius: 9, background: i < 3 ? `${medals[i]}22` : "rgba(150,170,220,0.06)", color: i < 3 ? medals[i] : C.inkDim, fontWeight: 900, fontSize: 14 }}>{i + 1}</div>
            <div style={{ flex: 1 }}>
              <div style={{ fontWeight: 800, fontSize: 14 }}>{r.nm}</div>
              <div style={{ fontSize: 11, color: C.inkDim }}>الدقّة {Math.round(r.acc * 100)}% {r.fastest != null && `· أسرع إجابة ${r.fastest.toFixed(1)}ث`}</div>
            </div>
            <div style={{ textAlign: "left" }}><div style={{ fontSize: 18, fontWeight: 900, color: C.gold }}>{r.right}</div><div style={{ fontSize: 10, color: C.inkDim }}>من {r.total}</div></div>
          </Panel>
        ))}
      </div>
      {fastestOverall && <div style={{ textAlign: "center", marginTop: 14, fontSize: 12.5, color: C.cyan, display: "flex", alignItems: "center", justifyContent: "center", gap: 6 }}><Icon d={I.bolt} size={15} c={C.cyan} />أسرع لاعب: {fastestOverall.nm} ({fastestOverall.fastest.toFixed(1)}ث)</div>}
      <GoldBtn onClick={() => { SFX.nav(); setScreen("challengeSetup"); }} style={{ marginTop: 20 }}>تحدٍّ جديد</GoldBtn>
      <DarkBtn onClick={() => setScreen("hub")} style={{ marginTop: 10 }}>الرئيسية</DarkBtn>
    </div>
  );
}

// ============ RESULT (single-player modes) ============
function Result({ result, setScreen, begin }) {
  const { right, total, perfect, xp, coin, gem, mode, headline } = result;
  const ic = perfect ? "crown" : right >= total * 0.6 ? "trophy" : "target";
  const vc = perfect ? C.gold : C.cyan;
  const verdict = headline || (perfect ? "إتقان كامل" : right >= total * 0.6 ? "أداء رائع" : "واصل التقدّم");
  return (
    <div className="k-fade" style={{ padding: 22, display: "flex", flexDirection: "column", justifyContent: "center", minHeight: "100vh", textAlign: "center" }}>
      <div className="k-pop" style={{ display: "grid", placeItems: "center", width: 92, height: 92, borderRadius: 26, margin: "0 auto", background: `radial-gradient(circle,${vc}22,transparent)`, border: `1px solid ${vc}44` }}><Icon d={I[ic]} size={48} c={vc} /></div>
      <h2 style={{ fontSize: 26, fontWeight: 900, margin: "14px 0 4px", color: vc }}>{verdict}</h2>
      <div style={{ color: C.inkDim, fontSize: 15 }}>{right} من {total} إجابة صحيحة</div>
      <Panel style={{ marginTop: 18, display: "flex", justifyContent: "space-around", padding: 18 }}>
        <div className="k-rise"><Icon d={I.star} size={22} c={C.cyan} /><div style={{ fontSize: 21, fontWeight: 900, color: C.cyan, marginTop: 4 }}>+{xp}</div><div style={{ fontSize: 11, color: C.inkDim }}>خبرة</div></div>
        <div className="k-rise"><Icon d={I.coin} size={22} c={C.gold} /><div style={{ fontSize: 21, fontWeight: 900, color: C.gold, marginTop: 4 }}>+{coin}</div><div style={{ fontSize: 11, color: C.inkDim }}>عملات</div></div>
        {gem > 0 && <div className="k-rise"><Icon d={I.gem} size={22} c={C.violet} /><div style={{ fontSize: 21, fontWeight: 900, color: C.violet, marginTop: 4 }}>+{gem}</div><div style={{ fontSize: 11, color: C.inkDim }}>جواهر</div></div>}
      </Panel>
      <GoldBtn onClick={() => { SFX.nav(); begin(mode, mode._cat); }} style={{ marginTop: 20, padding: "14px" }}>جولة جديدة</GoldBtn>
      <DarkBtn onClick={() => setScreen("hub")} style={{ marginTop: 10 }}>الرئيسية</DarkBtn>
    </div>
  );
}

