function Profile({ p, update, setScreen, acc, playerTier, diff, showToast }) {
  const s = p.stats;
  const [editing, setEditing] = useState(false);
  const [draftName, setDraftName] = useState(p.profile.name);
  const fav = favoriteCat(p);
  const rank = globalRank(p);
  const saveProfile = () => {
    const name = draftName.trim().slice(0, 24);
    if (!name) { showToast("أدخل اسماً صالحاً", C.red); return; }
    SFX.reward();
    update((n) => { n.profile = { ...n.profile, name }; });
    setEditing(false); showToast("تم حفظ ملفك الشخصي", C.green);
  };
  const setAv = (patch) => update((n) => { n.profile = { ...n.profile, ...patch }; });
  const facts = [
    { icon: "clock", l: "تاريخ الانضمام", v: fmtJoined(p.profile.joined), c: C.cyan },
    { icon: "hourglass", l: "وقت اللعب الكلي", v: fmtPlaytime(p.profile.playMs || 0), c: C.amber },
    { icon: fav ? fav.icon : "grid", l: "الفئة المفضلة", v: fav ? fav.name : "العب لتظهر", c: fav ? fav.color : C.inkDim },
    { icon: "bolt", l: "أطول سلسلة إجابات", v: `${s.bestStreak || 0} متتالية`, c: C.rose },
  ];
  return (
    <div className="k-fade" style={{ padding: 16 }}>
      <Header title="الملف الشخصي" onBack={() => setScreen("hub")} icon="user" right={<IconBtn icon="gear" onClick={() => setScreen("settings")} />} />
      <Panel glow={p.profile.color} style={{ textAlign: "center", padding: 20 }}>
        <div style={{ display: "grid", placeItems: "center" }}><Avatar profile={p.profile} size={76} /></div>
        <div style={{ fontSize: 21, fontWeight: 900, marginTop: 12 }}>{p.profile.name}</div>
        <div style={{ fontSize: 12.5, color: C.inkDim, marginTop: 2 }}>{rankFor(p.level)} · المستوى {p.level}</div>
        <div style={{ marginTop: 10, display: "flex", gap: 8, justifyContent: "center", flexWrap: "wrap" }}><TierTag d={playerTier} /><span style={{ fontSize: 11, fontWeight: 800, padding: "3px 10px", borderRadius: 8, background: `${diff.c}1c`, color: diff.c, border: `1px solid ${diff.c}44` }}>صعوبة: {diff.name}</span></div>
        <DarkBtn icon="feather" onClick={() => { setDraftName(p.profile.name); setEditing(!editing); }} style={{ marginTop: 14 }}>{editing ? "إغلاق التعديل" : "تعديل الاسم والصورة"}</DarkBtn>
      </Panel>

      {editing && (
        <Panel className="k-fade" glow={C.gold} style={{ padding: 16, marginTop: 12 }}>
          <div style={{ fontSize: 12.5, fontWeight: 800, marginBottom: 7 }}>الاسم</div>
          <input value={draftName} onChange={(e) => setDraftName(e.target.value)} maxLength={24} placeholder="اسم اللاعب"
            style={{ width: "100%", padding: "11px 13px", borderRadius: 11, background: "rgba(150,170,220,0.08)", border: `1px solid ${C.line2}`, color: C.ink, fontSize: 14, fontFamily: "inherit", outline: "none" }} aria-label="اسم اللاعب" />
          <div style={{ fontSize: 12.5, fontWeight: 800, margin: "14px 0 7px" }}>الأيقونة</div>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(6,1fr)", gap: 8 }}>
            {AVATAR_ICONS.map((ic) => (
              <button key={ic} className="k-press" onClick={() => { SFX.tap(); setAv({ icon: ic }); }} aria-label={`أيقونة ${ic}`}
                style={{ display: "grid", placeItems: "center", aspectRatio: "1", borderRadius: 12, cursor: "pointer", background: p.profile.icon === ic ? `${p.profile.color}2a` : "rgba(150,170,220,0.06)", border: `1.5px solid ${p.profile.icon === ic ? p.profile.color : C.line}` }}>
                <Icon d={I[ic]} size={21} c={p.profile.icon === ic ? p.profile.color : C.inkDim} />
              </button>
            ))}
          </div>
          <div style={{ fontSize: 12.5, fontWeight: 800, margin: "14px 0 7px" }}>اللون</div>
          <div style={{ display: "flex", gap: 9, flexWrap: "wrap" }}>
            {AVATAR_COLORS.map((cl) => (
              <button key={cl} className="k-press" onClick={() => { SFX.tap(); setAv({ color: cl }); }} aria-label="لون الصورة"
                style={{ width: 34, height: 34, borderRadius: "50%", cursor: "pointer", background: cl, border: p.profile.color === cl ? `3px solid ${C.ink}` : `2px solid transparent`, boxShadow: `0 3px 10px ${cl}55` }} />
            ))}
          </div>
          <div style={{ fontSize: 12.5, fontWeight: 800, margin: "14px 0 7px" }}>الإطار <span style={{ fontWeight: 400, color: C.inkDim }}>(يُفتح من المتجر)</span></div>
          <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
            {AVATAR_FRAMES.map((fr) => {
              const owned = fr.free || p.inventory.has(fr.id);
              const on = p.profile.frame === fr.id;
              return (
                <button key={fr.id} className="k-press" disabled={!owned} onClick={() => { if (!owned) return; SFX.tap(); setAv({ frame: fr.id }); }}
                  style={{ display: "flex", alignItems: "center", gap: 6, padding: "8px 12px", borderRadius: 10, cursor: owned ? "pointer" : "not-allowed", opacity: owned ? 1 : 0.5, fontFamily: "inherit", fontSize: 12, fontWeight: 800, color: on ? (fr.c || C.ink) : C.inkDim, background: on ? `${fr.c || C.gold}1c` : "rgba(150,170,220,0.06)", border: `1.5px solid ${on ? (fr.c || C.gold) : C.line}` }}>
                  {!owned && <Icon d={I.lock} size={12} c={C.inkFaint} />}{fr.name}
                </button>
              );
            })}
          </div>
          <GoldBtn onClick={saveProfile} style={{ marginTop: 16 }}>حفظ الملف</GoldBtn>
        </Panel>
      )}

      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 10, marginTop: 14 }}>
        <Mini icon="list" v={s.rounds} l="جولات" c={C.cyan} />
        <Mini icon="scroll" v={s.answered.toLocaleString("en")} l="أسئلة" c={C.gold} />
        <Mini icon="target" v={`${Math.round(acc * 100)}%`} l="الدقّة" c={C.green} />
        <Mini icon="check" v={s.right.toLocaleString("en")} l="إجابات صحيحة" c={C.green} />
        <Mini icon="star" v={s.perfects} l="إتقان" c={C.amber} />
        <Mini icon="fire" v={`${p.streak} يوم`} l="سلسلة الأيام" c={C.red} />
        <Mini icon="rank" v={rank ? `#${rank.toLocaleString("en")}` : "—"} l="الترتيب" c={C.violet} />
        <Mini icon="medal" v={`${s.achGot}/${ACHIEVEMENTS.length}`} l="إنجازات" c={C.rose} />
        <Mini icon="gem" v={p.gems} l="جواهر" c={C.cyan} />
      </div>

      <div style={{ display: "grid", gap: 8, marginTop: 12 }}>
        {facts.map((f) => (
          <Panel key={f.l} style={{ padding: 12, display: "flex", alignItems: "center", gap: 12 }}>
            <div style={{ display: "grid", placeItems: "center", width: 36, height: 36, borderRadius: 10, background: `${f.c}1a`, border: `1px solid ${f.c}33`, flexShrink: 0 }}><Icon d={I[f.icon]} size={18} c={f.c} /></div>
            <div style={{ flex: 1, fontSize: 13, fontWeight: 700, color: C.inkDim }}>{f.l}</div>
            <div style={{ fontSize: 13.5, fontWeight: 900 }}>{f.v}</div>
          </Panel>
        ))}
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 9, marginTop: 12 }}>
        <DarkBtn icon="trophy" onClick={() => setScreen("achievements")}>الإنجازات</DarkBtn>
        <DarkBtn icon="list" onClick={() => setScreen("statistics")}>الإحصائيات</DarkBtn>
      </div>
      <h3 style={{ fontSize: 15, marginTop: 22, marginBottom: 10, display: "flex", alignItems: "center", gap: 8 }}><Icon d={I.gem} size={18} c={C.violet} />إتقان المعرفة حسب الفئة</h3>
      <div style={{ display: "grid", gap: 8 }}>
        {[...CATEGORIES].sort((a, b) => (p.stats.mastery[b.id] || 0) - (p.stats.mastery[a.id] || 0)).slice(0, 6).map(c => { const m = (p.stats.mastery[c.id] || 0); const lvl = Math.min(5, Math.floor(m / 12)); return <Panel key={c.id} style={{ padding: 12, display: "flex", alignItems: "center", gap: 12 }}><Icon d={I[c.icon]} size={20} c={c.color} /><div style={{ flex: 1 }}><div style={{ display: "flex", justifyContent: "space-between", fontSize: 13, marginBottom: 5 }}><span style={{ fontWeight: 700 }}>{c.name}</span><span style={{ color: C.inkDim }}>مستوى {lvl}</span></div><Bar pct={((m % 12) / 12) * 100} c={c.color} h={6} /></div></Panel>; })}
      </div>
    </div>
  );
}
function Mini({ icon, v, l, c }) { return <Panel style={{ padding: 13, textAlign: "center" }}><Icon d={I[icon]} size={18} c={c} /><div style={{ fontSize: 17, fontWeight: 900, color: c, marginTop: 4 }}>{v}</div><div style={{ fontSize: 11, color: C.inkDim }}>{l}</div></Panel>; }

// ============ SETTINGS ============
const Row = ({ icon, c, title, sub, children }) => (
  <Panel style={{ padding: 14, display: "flex", alignItems: "center", gap: 12, marginBottom: 9 }}>
    <div style={{ display: "grid", placeItems: "center", width: 38, height: 38, borderRadius: 11, background: `${c}1a`, border: `1px solid ${c}33`, flexShrink: 0 }}><Icon d={I[icon]} size={19} c={c} /></div>
    <div style={{ flex: 1, minWidth: 0 }}><div style={{ fontWeight: 800, fontSize: 14 }}>{title}</div>{sub && <div style={{ fontSize: 11, color: C.inkDim, marginTop: 2 }}>{sub}</div>}</div>
    {children}
  </Panel>
);
const Toggle = ({ on, onChange, c = C.gold }) => (
  <button className="k-press" onClick={() => { SFX.tap(); onChange(!on); }} style={{ width: 46, height: 27, borderRadius: 16, background: on ? c : "rgba(150,170,220,0.18)", border: "none", cursor: "pointer", padding: 0, position: "relative", transition: "background .2s", flexShrink: 0 }}>
    <span style={{ position: "absolute", top: 3, [on ? "left" : "right"]: 3, width: 21, height: 21, borderRadius: "50%", background: "#fff", transition: "all .2s", boxShadow: "0 2px 5px rgba(0,0,0,.3)" }} />
  </button>
);
const Slider = ({ val, onChange, c = C.gold }) => (
  <input type="range" min={0} max={1} step={0.05} value={val} onChange={(e) => onChange(parseFloat(e.target.value))} style={{ width: 120, accentColor: c, cursor: "pointer" }} />
);
function Settings({ settings, setSettings, update, p, setScreen, showToast }) {
  const [confirmReset, setConfirmReset] = useState(false);
  const set = (k, v) => { SFX.tap(); setSettings(s => ({ ...s, [k]: v })); };
  const doReset = () => {
    SFX.levelup();
    update(n => {
      const keep = n.profile; // progress resets; the player's identity stays
      Object.assign(n, defaultPlayer());
      n.profile = { ...keep, playMs: 0, joined: Date.now() };
    });
    setConfirmReset(false); showToast("تمت إعادة ضبط التقدّم", C.red);
  };
  return (
    <div className="k-fade" style={{ padding: 16 }}>
      <Header title="الإعدادات" onBack={() => setScreen("hub")} icon="gear" />

      <SectionTitle icon="target" c={C.gold} t="مستوى الصعوبة" />
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 8, marginBottom: 6 }}>
        {DIFFICULTIES.map((d) => {
          const on = settings.difficulty === d.id;
          return <button key={d.id} className="k-press" onClick={() => set("difficulty", d.id)} style={{ padding: "11px 6px", borderRadius: 13, background: on ? `${d.c}22` : "rgba(150,170,220,0.05)", border: `1.5px solid ${on ? d.c : C.line}`, cursor: "pointer", fontFamily: "inherit", color: C.ink, textAlign: "center" }}>
            <div style={{ fontSize: 13.5, fontWeight: 800, color: on ? d.c : C.ink }}>{d.name}</div>
            <div style={{ fontSize: 9, color: C.inkDim, marginTop: 2 }}>تأثير ×{d.xpMul}</div>
          </button>;
        })}
      </div>
      <div style={{ fontSize: 11.5, color: C.inkDim, padding: "0 4px 14px", lineHeight: 1.6 }}>{diffById(settings.difficulty).desc}<br />يؤثّر على: تعقيد الأسئلة · تشابه الخيارات · الوقت · المكافآت · الخبرة.</div>

      <SectionTitle icon="volume" c={C.cyan} t="الصوت" />
      <Row icon="volume" c={C.cyan} title="مؤثرات الصوت" sub={`${Math.round(settings.sfxVol * 100)}%`}><Slider val={settings.sfxVol} onChange={(v) => set("sfxVol", v)} c={C.cyan} /></Row>
      <Row icon="music" c={C.violet} title="الموسيقى" sub={`${Math.round(settings.musicVol * 100)}%`}><Slider val={settings.musicVol} onChange={(v) => set("musicVol", v)} c={C.violet} /></Row>

      <SectionTitle icon="lang" c={C.green} t="اللغة والمظهر" />
      <Row icon="lang" c={C.green} title="اللغة" sub="لغة الواجهة">
        <div style={{ display: "flex", gap: 6 }}>
          {[["ar", "العربية"], ["en", "English"]].map(([v, lbl]) => <button key={v} className="k-press" onClick={() => set("language", v)} style={chip(settings.language === v, C.green)}>{lbl}</button>)}
        </div>
      </Row>
      <Row icon={settings.theme === "dark" ? "moon" : "sun"} c={C.amber} title="السمة" sub="فاتح / داكن">
        <div style={{ display: "flex", gap: 6 }}>
          {[["dark", "داكن"], ["light", "فاتح"]].map(([v, lbl]) => <button key={v} className="k-press" onClick={() => set("theme", v)} style={chip(settings.theme === v, C.amber)}>{lbl}</button>)}
        </div>
      </Row>

      <SectionTitle icon="bell" c={C.rose} t="الإشعارات" />
      <Row icon="bell" c={C.rose} title="المهام اليومية" sub="تذكير بالمهام الجديدة"><Toggle on={settings.notifDaily} onChange={(v) => set("notifDaily", v)} c={C.rose} /></Row>
      <Row icon="gift" c={C.rose} title="الأحداث والعروض" sub="عروض المتجر والمواسم"><Toggle on={settings.notifEvents} onChange={(v) => set("notifEvents", v)} c={C.rose} /></Row>
      <Row icon="versus" c={C.rose} title="دعوات التحدي" sub="إشعار عند تحدّيك"><Toggle on={settings.notifChallenge} onChange={(v) => set("notifChallenge", v)} c={C.rose} /></Row>

      <SectionTitle icon="eye" c={C.blue} t="إمكانية الوصول" />
      <Row icon="eye" c={C.blue} title="نص أكبر" sub="تكبير حجم الخط"><Toggle on={settings.largeText} onChange={(v) => set("largeText", v)} c={C.blue} /></Row>
      <Row icon="spark" c={C.blue} title="تباين عالٍ" sub="ألوان أوضح"><Toggle on={settings.highContrast} onChange={(v) => set("highContrast", v)} c={C.blue} /></Row>
      <Row icon="bolt" c={C.blue} title="تقليل الحركة" sub="إيقاف الحركات للراحة"><Toggle on={settings.reduceMotion} onChange={(v) => set("reduceMotion", v)} c={C.blue} /></Row>

      <SectionTitle icon="film" c={C.violet} t="جودة الرسوم" />
      <Row icon="film" c={C.violet} title="مستوى الرسوم المتحركة" sub="يوازن بين الجمال والأداء">
        <div style={{ display: "flex", gap: 6 }}>
          {[["high", "عالٍ"], ["medium", "متوسط"], ["off", "موفّر"]].map(([v, lbl]) => <button key={v} className="k-press" onClick={() => set("animQuality", v)} style={chip(settings.animQuality === v, C.violet)}>{lbl}</button>)}
        </div>
      </Row>

      <SectionTitle icon="user" c={C.gold} t="الحساب" />
      <Row icon="user" c={C.gold} title={p.profile.name} sub={`عضو منذ ${fmtJoined(p.profile.joined)}`}>
        <DarkBtn onClick={() => setScreen("profile")} style={{ width: "auto", padding: "8px 12px", fontSize: 12 }}>تعديل الملف</DarkBtn>
      </Row>

      <SectionTitle icon="refresh" c={C.red} t="إعادة الضبط" />
      {!confirmReset ? (
        <DarkBtn icon="trash" onClick={() => { SFX.tap(); setConfirmReset(true); }} style={{ borderColor: `${C.red}55`, color: C.red }}>إعادة ضبط التقدّم</DarkBtn>
      ) : (
        <Panel style={{ padding: 14, border: `1px solid ${C.red}44` }}>
          <div style={{ fontSize: 13.5, fontWeight: 700, marginBottom: 10, color: C.red }}>هل أنت متأكد؟ سيُمحى كل التقدّم نهائياً.</div>
          <div style={{ display: "flex", gap: 9 }}>
            <button className="k-press" onClick={doReset} style={{ flex: 1, padding: "11px", borderRadius: 12, background: C.red, color: "#fff", border: "none", fontWeight: 800, fontFamily: "inherit", cursor: "pointer" }}>نعم، احذف الكل</button>
            <DarkBtn onClick={() => { SFX.tap(); setConfirmReset(false); }}>إلغاء</DarkBtn>
          </div>
        </Panel>
      )}
      <div style={{ textAlign: "center", marginTop: 22, fontSize: 11, color: C.inkFaint }}>مملكة المعرفة · إصدار {APP_VERSION}</div>
    </div>
  );
}
const SectionTitle = ({ icon, c, t }) => <div style={{ display: "flex", alignItems: "center", gap: 8, margin: "18px 2px 10px", fontSize: 13, fontWeight: 800, color: C.inkDim }}><Icon d={I[icon]} size={16} c={c} />{t}</div>;
const chip = (on, c) => ({ padding: "7px 12px", borderRadius: 10, background: on ? `${c}22` : "rgba(150,170,220,0.06)", border: `1.5px solid ${on ? c : C.line}`, color: on ? c : C.inkDim, fontWeight: 800, fontSize: 12.5, fontFamily: "inherit", cursor: "pointer" });

// ============ ACHIEVEMENTS ============
function Achievements({ p, setScreen }) {
  const done = ACHIEVEMENTS.filter(a => achProgress(a, p).done).length;
  return (
    <div className="k-fade" style={{ padding: 16 }}>
      <Header title="الإنجازات" onBack={() => setScreen("hub")} icon="trophy" color={C.amber} />
      <Panel glow={C.amber} style={{ padding: 16, textAlign: "center", marginBottom: 14 }}>
        <div style={{ fontSize: 30, fontWeight: 900, color: C.amber }}>{done} / {ACHIEVEMENTS.length}</div>
        <div style={{ fontSize: 12, color: C.inkDim, marginBottom: 8 }}>إنجازات مكتملة</div>
        <Bar pct={(done / ACHIEVEMENTS.length) * 100} c={C.amber} h={8} />
      </Panel>
      <div style={{ display: "grid", gap: 9 }}>
        {ACHIEVEMENTS.map((a, i) => {
          const pr = achProgress(a, p);
          return (
            <Panel key={a.id} style={{ animationDelay: `${i * 25}ms`, padding: 13, display: "flex", alignItems: "center", gap: 12, opacity: pr.done ? 1 : 0.92 }} glow={pr.done ? a.c : null} className="k-card">
              <div style={{ display: "grid", placeItems: "center", width: 44, height: 44, borderRadius: 13, background: pr.done ? `${a.c}22` : "rgba(150,170,220,0.06)", border: `1px solid ${pr.done ? a.c : C.line}`, flexShrink: 0 }}><Icon d={I[pr.done ? a.icon : "lock"]} size={22} c={pr.done ? a.c : C.inkFaint} /></div>
              <div style={{ flex: 1 }}>
                <div style={{ fontWeight: 800, fontSize: 14, display: "flex", alignItems: "center", gap: 6 }}>{a.name}{pr.done && <Icon d={I.check} size={15} c={a.c} />}</div>
                <div style={{ fontSize: 11.5, color: C.inkDim, marginBottom: 6 }}>{a.desc}</div>
                <Bar pct={pr.pct} c={a.c} h={5} />
              </div>
              <div style={{ textAlign: "left", fontSize: 11, color: C.inkDim, minWidth: 44 }}>{Math.min(pr.v, a.goal)}/{a.goal}</div>
            </Panel>
          );
        })}
      </div>
    </div>
  );
}

// ============ LEADERBOARD ============
function Leaderboard({ p, setScreen }) {
  const [tab, setTab] = useState("global");
  const bots = useMemo(() => {
    const names = ["أبو فهد", "نورة", "خالد العتيبي", "ريم", "سلطان", "مها", "عبدالله", "لمى", "تركي", "جواهر", "يوسف", "دانة", "فيصل", "هند", "ماجد"];
    return names.map((nm, i) => ({ nm, score: 9800 - i * 540 + (i % 2 ? 120 : 0), lvl: 40 - i * 2 }));
  }, []);
  const me = { nm: p.profile.name, score: (p.seasonXp || 0) + p.level * 100 + (p.stats.right || 0) * 2, lvl: p.level, me: true };
  const list = tab === "friends" ? bots.slice(0, 6) : bots;
  const ranked = [...list, me].sort((a, b) => b.score - a.score);
  const medals = [C.gold, "#c0c7d4", "#cd7f47"];
  return (
    <div className="k-fade" style={{ padding: 16 }}>
      <Header title="لوحة المتصدّرين" onBack={() => setScreen("hub")} icon="rank" color={C.violet} />
      <div style={{ display: "flex", gap: 8, marginBottom: 14 }}>
        {[["global", "العالم"], ["friends", "الأصدقاء"]].map(([v, lbl]) => <button key={v} className="k-press" onClick={() => { SFX.tap(); setTab(v); }} style={{ flex: 1, padding: "10px", borderRadius: 12, background: tab === v ? `${C.violet}22` : "rgba(150,170,220,0.06)", border: `1.5px solid ${tab === v ? C.violet : C.line}`, color: tab === v ? C.violet : C.inkDim, fontWeight: 800, fontSize: 13, fontFamily: "inherit", cursor: "pointer" }}>{lbl}</button>)}
      </div>
      <div style={{ display: "grid", gap: 8 }}>
        {ranked.map((r, i) => (
          <Panel key={i} className="k-card" style={{ animationDelay: `${i * 20}ms`, padding: 12, display: "flex", alignItems: "center", gap: 12, border: r.me ? `1.5px solid ${C.gold}` : `1px solid ${C.line}` }} glow={i < 3 ? medals[i] : null}>
            <div style={{ display: "grid", placeItems: "center", width: 32, height: 32, borderRadius: 9, background: i < 3 ? `${medals[i]}22` : "rgba(150,170,220,0.06)", color: i < 3 ? medals[i] : C.inkDim, fontWeight: 900, fontSize: 14 }}>{i + 1}</div>
            <div style={{ display: "grid", placeItems: "center", width: 38, height: 38, borderRadius: 11, background: r.me ? `linear-gradient(135deg,${C.goldHi},${C.goldDeep})` : "rgba(150,170,220,0.06)" }}><Icon d={r.me ? I.crown : I.user} size={19} c={r.me ? "#1c1407" : C.inkDim} /></div>
            <div style={{ flex: 1 }}><div style={{ fontWeight: 800, fontSize: 14, color: r.me ? C.gold : C.ink }}>{r.nm}</div><div style={{ fontSize: 11, color: C.inkDim }}>المستوى {r.lvl}</div></div>
            <div style={{ textAlign: "left" }}><div style={{ fontSize: 16, fontWeight: 900, color: C.gold }}>{r.score.toLocaleString("en")}</div><div style={{ fontSize: 10, color: C.inkDim }}>نقطة</div></div>
          </Panel>
        ))}
      </div>
    </div>
  );
}

// ============ MISSIONS ============
function Missions({ p, update, setScreen, begin, showToast }) {
  const missions = dailyMissions(p);
  const claim = (ms) => {
    if (p.daily.claimedM.has(ms.id) || ms.cur < ms.goal) return;
    SFX.reward();
    update(n => {
      n.coins += ms.reward.coin || 0; n.gems += ms.reward.gem || 0;
      let nx = n.xp + (ms.reward.xp || 0), lv = n.level, leveled = false;
      while (nx >= lv * 120) { nx -= lv * 120; lv++; leveled = true; }
      n.xp = nx; n.level = lv; n._lv = leveled;
      n.daily = { ...n.daily, claimedM: new Set(n.daily.claimedM).add(ms.id) };
    });
    showToast("تم استلام مكافأة المهمة", ms.c);
  };
  const allClaimed = missions.every(ms => p.daily.claimedM.has(ms.id));
  return (
    <div className="k-fade" style={{ padding: 16 }}>
      <Header title="المهام اليومية" onBack={() => setScreen("hub")} icon="target" />
      <Panel glow={C.gold} style={{ padding: 14, display: "flex", alignItems: "center", gap: 12, marginBottom: 14 }}>
        <Icon d={I.clock} size={22} c={C.gold} />
        <div style={{ flex: 1 }}><div style={{ fontWeight: 800, fontSize: 14 }}>تتجدّد المهام كل يوم</div><div style={{ fontSize: 11.5, color: C.inkDim }}>أكمل المهام لكسب العملات والخبرة</div></div>
      </Panel>
      <div style={{ display: "grid", gap: 9 }}>
        {missions.map((ms, i) => {
          const done = ms.cur >= ms.goal; const claimed = p.daily.claimedM.has(ms.id);
          return (
            <Panel key={ms.id} className="k-card" style={{ animationDelay: `${i * 30}ms`, padding: 13 }} glow={done && !claimed ? ms.c : null}>
              <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
                <div style={{ display: "grid", placeItems: "center", width: 42, height: 42, borderRadius: 12, background: `${ms.c}1a`, border: `1px solid ${ms.c}33`, flexShrink: 0 }}><Icon d={I[ms.icon]} size={21} c={ms.c} /></div>
                <div style={{ flex: 1 }}>
                  <div style={{ fontWeight: 800, fontSize: 14 }}>{ms.name}</div>
                  <div style={{ display: "flex", alignItems: "center", gap: 8, marginTop: 5 }}>
                    <div style={{ flex: 1 }}><Bar pct={(Math.min(ms.cur, ms.goal) / ms.goal) * 100} c={ms.c} h={5} /></div>
                    <span style={{ fontSize: 10.5, color: C.inkDim }}>{Math.min(ms.cur, ms.goal)}/{ms.goal}</span>
                  </div>
                </div>
                <div style={{ display: "flex", flexDirection: "column", alignItems: "flex-end", gap: 4 }}>
                  <span style={{ fontSize: 11, fontWeight: 800, color: C.gold, display: "flex", alignItems: "center", gap: 3 }}><Icon d={I.coin} size={12} c={C.gold} />{ms.reward.coin}{ms.reward.gem ? ` +${ms.reward.gem}💎` : ""}</span>
                  {claimed ? <span style={{ fontSize: 11, color: C.green, fontWeight: 800, display: "flex", alignItems: "center", gap: 3 }}><Icon d={I.check} size={13} c={C.green} />مُستلم</span>
                    : <button className="k-press" disabled={!done} onClick={() => claim(ms)} style={{ padding: "6px 12px", borderRadius: 9, border: "none", background: done ? `linear-gradient(135deg,${C.goldHi},${C.goldDeep})` : "rgba(150,170,220,0.1)", color: done ? "#1c1407" : C.inkFaint, fontWeight: 800, fontSize: 11.5, cursor: done ? "pointer" : "not-allowed", fontFamily: "inherit" }}>استلام</button>}
                </div>
              </div>
            </Panel>
          );
        })}
      </div>
      {allClaimed && <div style={{ textAlign: "center", marginTop: 14, color: C.green, fontSize: 13, fontWeight: 700 }}>أكملت كل مهام اليوم! عُد غداً للمزيد.</div>}
      <GoldBtn onClick={() => begin(MODES[0], null)} style={{ marginTop: 16 }}>العب لإكمال المهام</GoldBtn>
    </div>
  );
}

// ============ STORE ============
function Store({ p, update, setScreen, showToast }) {
  const buy = (item) => {
    const cur = item.currency === "gem" ? p.gems : p.coins;
    if (item.owned && p.inventory.has(item.id)) { showToast("تملك هذا العنصر بالفعل", C.inkDim); return; }
    if (item.id === "e_full" && p.energy >= MAX_ENERGY) { showToast("طاقتك ممتلئة بالفعل", C.inkDim); return; }
    if (cur < item.price) { SFX.wrong(); showToast("رصيد غير كافٍ", C.red); return; }
    SFX.reward();
    update(n => {
      if (item.currency === "gem") n.gems -= item.price; else n.coins -= item.price;
      if (item.grantCoin) n.coins += item.grantCoin;
      if (item.grantGem) n.gems += item.grantGem;
      if (item.grantEnergy) n.energy = Math.min(MAX_ENERGY, n.energy + item.grantEnergy);
      if (item.grantBoost) n.boosts = { ...n.boosts, xp2: (n.boosts?.xp2 || 0) + item.grantBoost };
      if (item.owned) n.inventory = new Set(n.inventory).add(item.id);
    });
    showToast(item.grantBoost ? "معزّز ×2 جاهز لجولتك القادمة" : `تم شراء: ${item.name}`, C.gold);
  };
  const sections = [
    { title: "العملات", icon: "coin", c: C.gold, items: [
      { id: "c_s", name: "كيس عملات صغير", price: 20, currency: "gem", grantCoin: 1500, icon: "coin" },
      { id: "c_l", name: "صندوق عملات كبير", price: 80, currency: "gem", grantCoin: 8000, icon: "gift" },
    ]},
    { title: "الطاقة والمعزّزات", icon: "flame", c: C.amber, items: [
      { id: "e_full", name: "تعبئة الطاقة", desc: `تملأ طاقتك إلى ${MAX_ENERGY}`, price: 600, currency: "coin", grantEnergy: MAX_ENERGY, icon: "flame" },
      { id: "b_xp", name: "معزّز خبرة ×2", desc: p.boosts?.xp2 ? `لديك ${p.boosts.xp2} معزّز جاهز` : "يضاعف خبرة جولتك القادمة", price: 1200, currency: "coin", grantBoost: 1, icon: "bolt" },
    ]},
    { title: "إطارات الصورة الشخصية", icon: "crown", c: C.violet, items: [
      { id: "skin_royal", name: "الإطار الملكي الذهبي", desc: "يظهر حول صورتك في الملف", price: 150, currency: "gem", owned: true, icon: "crown" },
      { id: "skin_night", name: "إطار الليل البنفسجي", desc: "يظهر حول صورتك في الملف", price: 100, currency: "gem", owned: true, icon: "moon" },
    ]},
  ];
  return (
    <div className="k-fade" style={{ padding: 16 }}>
      <Header title="المتجر" onBack={() => setScreen("hub")} icon="cart" right={<div style={{ display: "flex", gap: 6 }}><Counter icon="coin" val={p.coins.toLocaleString("en")} c={C.gold} /><Counter icon="gem" val={p.gems} c={C.cyan} /></div>} />
      {sections.map((s) => (
        <div key={s.title}>
          <SectionTitle icon={s.icon} c={s.c} t={s.title} />
          <div style={{ display: "grid", gap: 9 }}>
            {s.items.map((it) => {
              const owned = it.owned && p.inventory.has(it.id);
              return (
                <Panel key={it.id} style={{ padding: 13, display: "flex", alignItems: "center", gap: 12 }}>
                  <div style={{ display: "grid", placeItems: "center", width: 44, height: 44, borderRadius: 13, background: `${s.c}1a`, border: `1px solid ${s.c}33`, flexShrink: 0 }}><Icon d={I[it.icon]} size={22} c={s.c} /></div>
                  <div style={{ flex: 1 }}><div style={{ fontWeight: 800, fontSize: 14 }}>{it.name}</div>{it.grantCoin ? <div style={{ fontSize: 11, color: C.inkDim }}>+{it.grantCoin.toLocaleString("en")} عملة</div> : it.desc ? <div style={{ fontSize: 11, color: C.inkDim }}>{it.desc}</div> : null}</div>
                  <button className="k-press" disabled={owned} onClick={() => buy(it)} style={{ display: "flex", alignItems: "center", gap: 4, padding: "9px 13px", borderRadius: 11, border: "none", background: owned ? "rgba(150,170,220,0.1)" : `linear-gradient(135deg,${C.goldHi},${C.goldDeep})`, color: owned ? C.inkDim : "#1c1407", fontWeight: 800, fontSize: 12.5, cursor: owned ? "default" : "pointer", fontFamily: "inherit" }}>
                    {owned ? "مملوك" : <><Icon d={I[it.currency === "gem" ? "gem" : "coin"]} size={13} c="#1c1407" />{it.price}</>}
                  </button>
                </Panel>
              );
            })}
          </div>
        </div>
      ))}
    </div>
  );
}

// ============ SEASONS / PASS ============
const SEASON_PASS_PRICE = 250; // gems
function Seasons({ p, update, setScreen, showToast }) {
  const tiers = Array.from({ length: 12 }, (_, i) => ({ tier: i + 1, free: i % 2 === 0 ? { coin: 300 } : { gem: 2 }, prem: i % 3 === 0 ? { gem: 5 } : { coin: 800 } }));
  const seasonXp = p.seasonXp || 0;
  const cur = Math.min(12, Math.floor(seasonXp / 500)); // tier derives from season XP — always in sync
  const premium = !!p.seasonPremium;
  const grant = (r) => update((n) => { n.coins += r.coin || 0; n.gems += r.gem || 0; });
  const claim = (t, isPrem) => {
    const set = isPrem ? p.daily.claimedP : p.daily.claimedS;
    if (t.tier > cur || set.has(t.tier) || (isPrem && !premium)) return;
    SFX.reward(); grant(isPrem ? t.prem : t.free);
    update((n) => {
      const key = isPrem ? "claimedP" : "claimedS";
      n.daily = { ...n.daily, [key]: new Set(n.daily[key]).add(t.tier) };
    });
    showToast("تم استلام مكافأة المرتبة", isPrem ? C.gold : C.cyan);
  };
  const buyPass = () => {
    if (premium) return;
    if (p.gems < SEASON_PASS_PRICE) { SFX.wrong(); showToast(`تحتاج ${SEASON_PASS_PRICE} جوهرة للمسار المميّز`, C.red); return; }
    SFX.levelup();
    update((n) => { n.gems -= SEASON_PASS_PRICE; n.seasonPremium = true; });
    showToast("فُتح المسار المميّز — مكافآت مضاعفة!", C.gold);
  };
  return (
    <div className="k-fade" style={{ padding: 16 }}>
      <Header title="موسم التحف" onBack={() => setScreen("hub")} icon="shield" color={C.cyan} />
      <Panel glow={C.cyan} style={{ padding: 16, marginBottom: 14 }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 10 }}>
          <div><div style={{ fontWeight: 900, fontSize: 16 }}>المرتبة {cur}</div><div style={{ fontSize: 11.5, color: C.inkDim }}>اكسب الخبرة من أي وضع لعب لترتقي</div></div>
          <span style={{ padding: "4px 11px", borderRadius: 9, background: premium ? `${C.gold}2a` : `${C.cyan}1c`, color: premium ? C.gold : C.cyan, border: `1px solid ${premium ? C.gold : C.cyan}44`, fontSize: 11.5, fontWeight: 800 }}>{premium ? "المسار المميّز ✓" : "المسار المجاني"}</span>
        </div>
        <Bar pct={cur >= 12 ? 100 : ((seasonXp % 500) / 500) * 100} c={C.cyan} h={8} />
        <div style={{ fontSize: 11, color: C.inkDim, marginTop: 6, textAlign: "center" }}>{cur >= 12 ? "أكملت كل مراتب الموسم!" : `${seasonXp % 500} / 500 خبرة للمرتبة التالية`}</div>
      </Panel>
      {!premium && <GoldBtn onClick={buyPass} style={{ marginBottom: 16 }}>فتح المسار المميّز — {SEASON_PASS_PRICE} جوهرة</GoldBtn>}
      <div style={{ display: "grid", gap: 9 }}>
        {tiers.map((t) => {
          const unlocked = t.tier <= cur;
          return (
            <Panel key={t.tier} style={{ padding: 12, display: "flex", alignItems: "center", gap: 12, opacity: unlocked ? 1 : 0.85 }} glow={unlocked ? C.cyan : null}>
              <div style={{ display: "grid", placeItems: "center", width: 36, height: 36, borderRadius: 11, background: unlocked ? `${C.cyan}22` : "rgba(150,170,220,0.06)", color: unlocked ? C.cyan : C.inkFaint, fontWeight: 900, fontSize: 14, flexShrink: 0, border: `1px solid ${unlocked ? C.cyan : C.line}` }}>{t.tier}</div>
              <div style={{ flex: 1, display: "flex", gap: 8 }}>
                <RewardChip r={t.free} c={C.cyan} claimed={p.daily.claimedS.has(t.tier)} claimable={unlocked && !p.daily.claimedS.has(t.tier)} onClaim={() => claim(t, false)} />
                <RewardChip r={t.prem} c={C.gold} claimed={p.daily.claimedP.has(t.tier)} claimable={premium && unlocked && !p.daily.claimedP.has(t.tier)} locked={!premium} onClaim={() => claim(t, true)} />
              </div>
              {unlocked ? <Icon d={I.check} size={20} c={C.green} /> : <Icon d={I.lock} size={18} c={C.inkFaint} />}
            </Panel>
          );
        })}
      </div>
    </div>
  );
}
const RewardChip = ({ r, c, claimed, claimable, locked, onClaim }) => (
  <button className={claimable ? "k-press" : ""} disabled={!claimable} onClick={() => claimable && onClaim()}
    style={{ flex: 1, display: "flex", alignItems: "center", gap: 6, padding: "7px 9px", borderRadius: 10, fontFamily: "inherit", cursor: claimable ? "pointer" : "default", background: claimable ? `${c}22` : locked ? "rgba(150,170,220,0.05)" : `${c}10`, border: claimable ? `1.5px solid ${c}` : `1px dashed ${locked ? C.line : c + "55"}`, opacity: claimed ? 0.55 : 1 }}>
    <Icon d={I[claimed ? "check" : r.gem ? "gem" : "coin"]} size={15} c={locked && !claimable ? C.inkFaint : c} />
    <div style={{ fontSize: 12, fontWeight: 800, color: locked && !claimable ? C.inkFaint : C.ink }}>{claimed ? "مُستلم" : r.gem ? `${r.gem} جوهرة` : `${r.coin} عملة`}</div>
    {claimable && <span style={{ fontSize: 10, fontWeight: 900, color: c, marginInlineStart: "auto" }}>استلام</span>}
  </button>
);

// ============ STATISTICS ============
function Statistics({ p, acc, setScreen }) {
  const s = p.stats;
  const recent = p.history.slice(0, 12);
  const recentAcc = recent.length ? recent.filter(h => h.ok).length / recent.length : 0;
  return (
    <div className="k-fade" style={{ padding: 16 }}>
      <Header title="الإحصائيات" onBack={() => setScreen("hub")} icon="list" color={C.green} />
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10, marginBottom: 12 }}>
        <Mini icon="play" v={s.rounds} l="إجمالي الجولات" c={C.cyan} />
        <Mini icon="scroll" v={s.answered.toLocaleString("en")} l="أسئلة مجابة" c={C.gold} />
        <Mini icon="target" v={`${Math.round(acc * 100)}%`} l="الدقّة الكلية" c={C.green} />
        <Mini icon="star" v={s.perfects} l="جولات كاملة" c={C.amber} />
        <Mini icon="fire" v={`${p.streak} يوم`} l="السلسلة" c={C.red} />
        <Mini icon="tower" v={s.towerBest || 0} l="أعلى طابق" c={C.blue} />
        <Mini icon="fingerprint" v={s.casesSolved || 0} l="قضايا محلولة" c={C.violet} />
        <Mini icon="shield" v={s.bossWins || 0} l="زعماء مهزومون" c={C.rose} />
      </div>
      <Panel glow={C.green} style={{ padding: 16, marginBottom: 12 }}>
        <div style={{ fontSize: 13, fontWeight: 800, marginBottom: 10 }}>الدقّة في آخر {recent.length || 0} سؤال</div>
        <div style={{ display: "flex", alignItems: "flex-end", gap: 4, height: 60 }}>
          {recent.length ? recent.slice().reverse().map((h, i) => <div key={i} style={{ flex: 1, height: h.ok ? "100%" : "34%", borderRadius: 4, background: h.ok ? C.green : `${C.red}99`, transition: "height .4s" }} />) : <div style={{ color: C.inkDim, fontSize: 12 }}>لا يوجد سجل بعد — العب جولة!</div>}
        </div>
        {recent.length > 0 && <div style={{ marginTop: 8, fontSize: 11.5, color: C.inkDim, textAlign: "center" }}>الدقّة الأخيرة: {Math.round(recentAcc * 100)}%</div>}
      </Panel>
      <h3 style={{ fontSize: 14, margin: "14px 2px 10px", fontWeight: 800 }}>الأداء حسب الفئة</h3>
      <div style={{ display: "grid", gap: 8 }}>
        {CATEGORIES.map(c => { const m = (s.mastery[c.id] || 0); const lvl = Math.min(5, Math.floor(m / 12)); return (
          <Panel key={c.id} style={{ padding: 11, display: "flex", alignItems: "center", gap: 11 }}>
            <Icon d={I[c.icon]} size={19} c={c.color} />
            <div style={{ flex: 1 }}><div style={{ display: "flex", justifyContent: "space-between", fontSize: 12.5, marginBottom: 4 }}><span style={{ fontWeight: 700 }}>{c.name}</span><span style={{ color: C.inkDim }}>{m} إجابة · مستوى {lvl}</span></div><Bar pct={((m % 12) / 12) * 100} c={c.color} h={5} /></div>
          </Panel>
        ); })}
      </div>
    </div>
  );
}

